type Bullet = { id:string; x:number; y:number; kind:'normal'|'gold' }
type PowerUpKind = 'boots' | 'golden_glove'
type PowerUpState = 'waiting' | 'active' | 'collected' | 'expired'
type PowerUp = { id:string; kind:PowerUpKind; x:number; y:number; spawnDelay:number; state:PowerUpState }
type TackleWave = { id:string; x:number; width:number }
type ExplosionBurst = { id:string; x:number; y:number; radius:number }
