  const totalRef=useRef(initial.length),endedRef=useRef(false),enemiesRef=useRef(enemies),bulletsRef=useRef<Bullet[]>([]),powerUpsRef=useRef<PowerUp[]>(initialPowerUps),remainingMsRef=useRef(cfg.timer*1000),passedRef=useRef(0),destroyedRef=useRef(0),rapidUntilRef=useRef(0),goldShotsRef=useRef(0),phaseRef=useRef<'invaders'|'goal_save'>('invaders'),goalSaveRef=useRef(false),containerRef=useRef<HTMLDivElement>(null),frameRef=useRef(0),startRef=useRef<number|null>(null),xRef=useRef(50),lastFireRef=useRef(0),pausedRef=useRef(false),keysRef=useRef({left:false,right:false}),keyHoldStartRef=useRef<{left:number|null;right:number|null}>({left:null,right:null}),dashTimerRef=useRef<ReturnType<typeof setTimeout>|null>(null),chargeStartRef=useRef<number|null>(null),cooldownUntilRef=useRef(0),lightningCooldownUntilRef=useRef(0),finishDelayRef=useRef<ReturnType<typeof setTimeout>|null>(null),timersRef=useRef<ReturnType<typeof setTimeout>[]>([])
  enemiesRef.current=enemies; powerUpsRef.current=powerUps; pausedRef.current=isPaused??false
  const timer=useCallback((fn:()=>void,ms:number)=>{const t=setTimeout(fn,ms);timersRef.current.push(t);return t},[])
  useEffect(()=>()=>{cancelAnimationFrame(frameRef.current);timersRef.current.forEach(clearTimeout)},[])
