  const finish=useCallback((outcome:DefenseOutcome)=>{if(endedRef.current)return;endedRef.current=true;cancelAnimationFrame(frameRef.current);onRoundEnd(outcome)},[onRoundEnd])
  const triggerGoalSave=useCallback(()=>{if(endedRef.current||showGoalSaveIntro)return;goalSaveRef.current=true;cancelAnimationFrame(frameRef.current);setShowGoalSaveIntro(true)},[showGoalSaveIntro])
